  for (let i = 0; i < s.length; i++) cnt[s.charCodeAt(i) - 97]++;
  let mx = 0;
  for (let v of cnt) if (v > mx) mx = v;
  results.push(String(s.length - mx));
}
console.log(results.join('\n'));

